code = """import json

# Access the stored results using the correct keys
cases = locals()['var_functions.query_db:5']
order_items = locals()['var_functions.query_db:11']

# Extract order item IDs for the product
order_item_ids = [item['Id'] for item in order_items]

# Filter cases where orderitemid__c is in our order item list
# Also handle potential corruption (leading # and trailing whitespace)
filtered_cases = []
for case in cases:
    case_orderitem_id = case['orderitemid__c']
    if case_orderitem_id:
        # Normalize ID (remove leading # and trailing whitespace)
        normalized_case_id = case_orderitem_id.lstrip('#').strip()
        for order_item_id in order_item_ids:
            normalized_order_item_id = order_item_id.lstrip('#').strip()
            if normalized_case_id == normalized_order_item_id:
                filtered_cases.append(case)
                break

# Count occurrences of each issueid__c
issue_counts = {}
for case in filtered_cases:
    issue_id = case['issueid__c']
    if issue_id:
        issue_counts[issue_id] = issue_counts.get(issue_id, 0) + 1

# Find the most frequent issue
if issue_counts:
    most_frequent_issue_id = max(issue_counts, key=issue_counts.get)
    result = most_frequent_issue_id
else:
    result = None

print('__RESULT__:')
print(json.dumps(result))"""

